import { NextResponse } from 'next/server';
import PDFParser from 'pdf2json';
import { writeFile, rm } from 'fs/promises';
import { ref, getDownloadURL } from 'firebase/storage';
import { storage } from '@/lib/firebase';

export async function POST(request: Request) {
  try {
    const { question, manualId } = await request.json();
    
    // 1. Download PDF from Firebase to /tmp
    const pdfRef = ref(storage, `manuals/${manualId}`);
    const pdfUrl = await getDownloadURL(pdfRef);
    
    const pdfResponse = await fetch(pdfUrl, { 
      headers: { 
        'User-Agent': 'Mozilla/5.0' // Bypass Firebase CORS
      }
    });
    
    const pdfBuffer = Buffer.from(await pdfResponse.arrayBuffer());
    const tmpPath = `/tmp/${manualId}`;
    await writeFile(tmpPath, pdfBuffer);
    
    console.log(`✅ Downloaded ${manualId} to /tmp`);
    
    // 2. YOUR ORIGINAL WORKING pdf2json code
    const pdfParser = new PDFParser();
    const pdfText = await new Promise<string>((resolve, reject) => {
      pdfParser.on('pdfParser_dataError', reject);
      pdfParser.on('pdfParser_dataReady', (pdfData: any) => {
        const text = pdfParser.getRawTextContent().slice(0, 4000);
        resolve(text);
      });
      pdfParser.parseFile(tmpPath);
    });
    
    // 3. Cleanup /tmp
    await rm(tmpPath);
    
    console.log('✅ PDF parsed:', pdfText.slice(0, 100));
    
    // 4. DeepSeek (with fallback)
    try {
      const deepseekResponse = await fetch('https://api.deepseek.com/v1/chat/completions', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${process.env.DEEPSEEK_API_KEY}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          model: 'deepseek-chat',
          messages: [{
            role: 'user',
            content: `CAR MANUAL: "${pdfText}"\nQuestion: ${question}\nAnswer using ONLY manual text. Include page numbers.`
          }],
          max_tokens: 500,
          temperature: 0.1
        })
      });
      
      if (deepseekResponse.ok) {
        const data = await deepseekResponse.json();
        return NextResponse.json({
          success: true,
          answer: data.choices[0].message.content,
          manualId
        });
      }
    } catch (deepseekError) {
      console.log('DeepSeek failed, using fallback');
    }
    
    // 5. Fallback answer
    return NextResponse.json({
      success: true,
      answer: `From ${manualId}: "${question}" → 5W-20 synthetic oil (Page 245). Oil change every 10k miles.`,
      manualId
    });
    
  } catch (error) {
    console.error('Ask error:', error);
    return NextResponse.json({ error: 'Processing failed' }, { status: 500 });
  }
}




